const mk = () => require("./transaction").createTransaction()
const run = (name, lines) => new Promise(res => {
  const t = mk()
  for (const l of lines) t.add_data(Buffer.from(l, "utf8"))
  t.end_data(() => {
    console.log("---", name)
    console.log("  subject=", JSON.stringify(t.header.get("subject")), "from=", JSON.stringify(t.header.get("from")))
    t.message_stream.get_data(d => { console.log("  MSG=", JSON.stringify(d.toString())); res() })
  })
})
;(async () => {
  await run("BOM first line", ["﻿Received: from x\r\n","Subject: hello\r\n","From: a@b.com\r\n","\r\n","the body\r\n"])
  await run("malformed mid-header line", ["Received: from x\r\n","This is not a header\r\n","Subject: hello\r\n","From: a@b.com\r\n","\r\n","the body\r\n"])
  await run("empty transaction", [])
})()
'

